import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { getCorsHeaders, jsonResponse } from "../_shared/cors.ts";
import { checkRateLimit } from "../_shared/rate-limit.ts";
import { photoToScopeSchema } from "../_shared/validation.ts";
import {
  assertProjectOwner,
  getServiceClient,
  getUserIdFromRequest,
} from "../_shared/auth.ts";
import {
  cityFromZip,
  extractScopeWithGemini,
  type RoomType,
} from "./_shared/estimate.ts";
import { type GeminiPart } from "../_shared/gemini.ts";

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: getCorsHeaders(req) });
  }
  if (req.method !== "POST") {
    return jsonResponse({ error: "Method not allowed" }, 405, req);
  }

  const { ok, retryAfter } = checkRateLimit(req);
  if (!ok) {
    return jsonResponse(
      { error: "Too many requests. Please try again later." },
      429,
      req,
      retryAfter ?? 60,
    );
  }

  try {
    const formData = await req.formData();
    const photos = formData.getAll("photos[]").length
      ? formData.getAll("photos[]")
      : formData.getAll("photos");
    const photoCount = Array.from(photos).filter(
      (p) => p instanceof File && p.size > 0,
    ).length;
    console.log(`[photo-to-scope] Received ${photoCount} photos, zip: ${formData.get("zip_code")}, room: ${formData.get("room_type")}`);

    const parsed = photoToScopeSchema.safeParse({
      zip_code: String(formData.get("zip_code") ?? "").trim() || "00000",
      room_type: String(formData.get("room_type") ?? "other"),
      finish_preference: String(formData.get("finish_preference") ?? "mid"),
      project_id: (formData.get("project_id") as string | null)?.trim() || null,
      location_unset: String(formData.get("location_unset") ?? ""),
      scope_description: (formData.get("scope_description") as string | null)?.trim() || null,
    });

    if (!parsed.success) {
      const msg = parsed.error.errors[0]?.message ?? "Invalid request";
      return jsonResponse({ error: msg }, 400, req);
    }

    const { zip_code, room_type, finish_preference, project_id, location_unset, scope_description } = parsed.data;
    const projectId = project_id ?? null;

    let payload = null;

    // 1. Try Gemini if photos or description provided
    const photoParts: GeminiPart[] = [];
    for (const p of photos) {
      if (p instanceof File && p.size > 0) {
        const buf = await p.arrayBuffer();
        const bytes = new Uint8Array(buf);
        let binary = "";
        const chunkSize = 8192;
        for (let i = 0; i < bytes.length; i += chunkSize) {
          binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
        }
        const base64 = btoa(binary);
        photoParts.push({
          inline_data: {
            mime_type: p.type || "image/jpeg",
            data: base64,
          },
        });
      }
    }

    // 1. Call Gemini for estimation
    payload = await extractScopeWithGemini({
      room_type: room_type as RoomType,
      zip_code,
      finish_preference,
      scopeDescription: scope_description,
      photoParts,
    });

    if (!payload) {
      return jsonResponse({ 
        error: "AI estimation failed. Please try adding a description or better photos." 
      }, 500, req);
    }

    if ((payload as any).error) {
      return jsonResponse({ 
        error: `AI Service Error: ${(payload as any).error}` 
      }, 500, req);
    }

    if (projectId) {
      const userId = await getUserIdFromRequest(req);
      if (!userId) {
        return jsonResponse({ error: "Sign in to save this to a project." }, 401, req);
      }
      const admin = getServiceClient();
      try {
        await assertProjectOwner(admin, projectId, userId);
      } catch (e) {
        const m = e instanceof Error ? e.message : "";
        if (m === "not_found") return jsonResponse({ error: "Project not found" }, 404, req);
        return jsonResponse({ error: "Access denied" }, 403, req);
      }

      await admin.from("scope_items").delete().eq("project_id", projectId);

      const rows = payload.scope_items.map((s) => ({
        project_id: projectId,
        category: s.category,
        description: s.description,
        finish_tier: s.finish_tier,
        quantity: s.quantity,
        unit: s.unit,
        unit_cost_min: s.unit_cost_min,
        unit_cost_max: s.unit_cost_max,
        total_cost_min: s.total_cost_min,
        total_cost_max: s.total_cost_max,
        confidence_score: s.confidence_score,
        source: s.source,
      }));

      const { data: inserted, error: insErr } = await admin
        .from("scope_items")
        .insert(rows)
        .select("id, category, description, finish_tier, quantity, unit, unit_cost_min, unit_cost_max, total_cost_min, total_cost_max, confidence_score, source");

      if (insErr) {
        console.error(insErr);
        return jsonResponse({ error: "Could not save scope" }, 500, req);
      }

      await admin
        .from("projects")
        .update({
          estimated_min_total: payload.summary.estimated_min_total,
          estimated_max_total: payload.summary.estimated_max_total,
          confidence_score: payload.summary.confidence_score,
          updated_at: new Date().toISOString(),
        })
        .eq("id", projectId);

      const scope_items = (inserted ?? []).map((r: {
        id: string;
        category: string;
        description: string;
        finish_tier: string;
        quantity: number;
        unit: string;
        unit_cost_min: number;
        unit_cost_max: number;
        total_cost_min: number;
        total_cost_max: number;
        confidence_score: number;
        source: string;
      }) => ({
        id: r.id,
        category: r.category,
        description: r.description,
        finish_tier: r.finish_tier,
        quantity: r.quantity,
        unit: r.unit,
        unit_cost_min: r.unit_cost_min,
        unit_cost_max: r.unit_cost_max,
        total_cost_min: r.total_cost_min,
        total_cost_max: r.total_cost_max,
        confidence_score: r.confidence_score,
        source: r.source,
      }));

      return jsonResponse(
        {
          project_id: projectId,
          summary: payload.summary,
          scope_items,
          explanations: payload.explanations,
        },
        200,
        req,
      );
    }

    const scope_items = payload.scope_items.map((s, i) => ({
      id: `scope_${i + 1}`,
      ...s,
    }));

    return jsonResponse(
      {
        project_id: null,
        summary: payload.summary,
        scope_items,
        explanations: payload.explanations,
        area_label: cityFromZip(zip_code),
      },
      200,
      req,
    );
  } catch (e: any) {
    console.error("[photo-to-scope] Global Error:", e);
    return jsonResponse(
      { error: `Internal Handler Error: ${e.message || "Unknown"}`, stack: e.stack },
      500,
      req,
    );
  }
});

import { callGemini, type GeminiPart } from "../../_shared/gemini.ts";

export type RoomType = "kitchen" | "bathroom" | "other";

export function cityFromZip(zip: string): string {
  const z = zip.replace(/\D/g, "").slice(0, 5);
  if (z.length >= 3) {
    const n = parseInt(z.slice(0, 3), 10);
    if (n >= 100 && n <= 199) return "your area";
    if (n >= 900 && n <= 961) return "Los Angeles area";
    if (n >= 430 && n <= 459) return "Columbus area";
  }
  return "your area";
}

export interface EstimatePayload {
  summary: {
    estimated_min_total: number;
    estimated_max_total: number;
    confidence_score: number;
  };
  scope_items: Array<{
    category: string;
    description: string;
    finish_tier: "economy" | "mid" | "premium";
    quantity: number;
    unit: string;
    unit_cost_min: number;
    unit_cost_max: number;
    total_cost_min: number;
    total_cost_max: number;
    confidence_score: number;
    source: "photo";
  }>;
  explanations: string[];
}

export async function extractScopeWithGemini(input: {
  room_type: RoomType;
  zip_code: string;
  finish_preference: "economy" | "mid" | "premium";
  scopeDescription?: string | null;
  photoParts?: GeminiPart[];
}): Promise<EstimatePayload | null> {
  const { room_type, zip_code, finish_preference, scopeDescription, photoParts = [] } = input;

  const systemInstruction = `You are an expert residential construction estimator at BLUPRNT.AI.
Analyze the project details and photos to generate a detailed, line-by-line cost estimate.

CRITICAL: Use your Google Search tool to find CURRENT market labor rates and material costs for ${room_type} renovations in the ${zip_code} area (or city). 
Do NOT rely on general averages if local data is available via search.

Guidelines:
1. Provide 6-12 detailed line items.
2. If photos are provided, explicitly mention visible features.
3. Ensure totals match (quantity * unit_cost).
4. Summary total must be the sum of all line items.`;

  const prompt = `Project: ${room_type} in Zip Code: ${zip_code}.
Finish Level: ${finish_preference}.
User Description: ${scopeDescription || "Analyze photos and search for contemporary local rates"}.`;

  const responseSchema = {
    type: "object",
    properties: {
      summary: {
        type: "object",
        properties: {
          estimated_min_total: { type: "number" },
          estimated_max_total: { type: "number" },
          confidence_score: { type: "number", description: "1 to 5" }
        },
        required: ["estimated_min_total", "estimated_max_total", "confidence_score"]
      },
      scope_items: {
        type: "array",
        items: {
          type: "object",
          properties: {
            category: { type: "string" },
            description: { type: "string" },
            finish_tier: { type: "string", enum: ["economy", "mid", "premium"] },
            quantity: { type: "number" },
            unit: { type: "string" },
            unit_cost_min: { type: "number" },
            unit_cost_max: { type: "number" },
            total_cost_min: { type: "number" },
            total_cost_max: { type: "number" },
            confidence_score: { type: "number" }
          },
          required: ["category", "description", "finish_tier", "quantity", "unit", "unit_cost_min", "unit_cost_max", "total_cost_min", "total_cost_max"]
        }
      },
      explanations: {
        type: "array",
        items: { type: "string" }
      }
    },
    required: ["summary", "scope_items", "explanations"]
  };

  const parts: GeminiPart[] = [{ text: prompt }, ...photoParts];

  try {
    const result = await callGemini({
      parts,
      systemInstruction,
      responseSchema,
      temperature: 0.1,
      useGrounding: true,
    });

    if (!result) return null;
    if (result.text.startsWith("ERROR:")) {
        console.error("Gemini Error:", result.text);
        return { error: result.text };
    }
    if (!result.text) return null;
    const text = result.text;

    let parsed = result.data;
    if (!parsed) {
        try {
            parsed = JSON.parse(text);
        } catch (e) {
            console.error("JSON parse failed in estimate:", e);
            return null;
        }
    }

    return {
      summary: {
        estimated_min_total: Math.round(Number(parsed.summary.estimated_min_total)),
        estimated_max_total: Math.round(Number(parsed.summary.estimated_max_total)),
        confidence_score: Number(parsed.summary.confidence_score),
      },
      scope_items: parsed.scope_items.map((s: any) => ({
        category: String(s.category),
        description: String(s.description),
        finish_tier: finish_preference,
        quantity: Number(s.quantity),
        unit: String(s.unit),
        unit_cost_min: Math.round(Number(s.unit_cost_min)),
        unit_cost_max: Math.round(Number(s.unit_cost_max)),
        total_cost_min: Math.round(Number(s.total_cost_min)),
        total_cost_max: Math.round(Number(s.total_cost_max)),
        confidence_score: Number(s.confidence_score || 3),
        source: "photo" as const,
      })),
      explanations: Array.isArray(parsed.explanations) ? parsed.explanations.map(String) : [],
    };
  } catch (e) {
    console.error("Gemini scope extraction failed:", e);
    return null;
  }
}

/**
 * CORS headers – restricts to allowed origins for security.
 * Set ALLOWED_ORIGINS env (comma-separated) or falls back to * for dev.
 */
function getAllowedOrigin(requestOrigin: string | null): string {
  const allowed = Deno.env.get("ALLOWED_ORIGINS");
  if (!allowed?.trim()) {
    return "*";
  }
  const origins = allowed.split(",").map((o) => o.trim()).filter(Boolean);
  if (origins.length === 0) return "*";
  if (requestOrigin && origins.includes(requestOrigin)) {
    return requestOrigin;
  }
  return origins[0];
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("Origin");
  return {
    "Access-Control-Allow-Origin": getAllowedOrigin(origin),
    "Access-Control-Allow-Headers":
      "authorization, x-client-info, apikey, content-type",
    "Access-Control-Allow-Methods": "POST, GET, OPTIONS",
    "Access-Control-Max-Age": "86400",
  };
}

export function jsonResponse(
  body: unknown,
  status: number,
  req: Request,
  retryAfter?: number,
): Response {
  const headers: Record<string, string> = {
    ...getCorsHeaders(req),
    "Content-Type": "application/json",
  };
  if (retryAfter != null && status === 429) {
    headers["Retry-After"] = String(retryAfter);
  }
  return new Response(JSON.stringify(body), { status, headers });
}

/**
 * In-memory rate limiter per Edge Function instance.
 * For production at scale, use Redis/Upstash or Supabase KV.
 * Set RATE_LIMIT_REQUESTS (default 60) and RATE_LIMIT_WINDOW_MS (default 60000).
 */
const store = new Map<string, { count: number; resetAt: number }>();

const REQUESTS = parseInt(Deno.env.get("RATE_LIMIT_REQUESTS") ?? "60", 10);
const WINDOW_MS = parseInt(Deno.env.get("RATE_LIMIT_WINDOW_MS") ?? "60000", 10);

function getClientId(req: Request): string {
  return (
    req.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ??
    req.headers.get("cf-connecting-ip") ??
    req.headers.get("x-real-ip") ??
    "unknown"
  );
}

export function checkRateLimit(req: Request): { ok: boolean; retryAfter?: number } {
  const id = getClientId(req);
  const now = Date.now();
  const entry = store.get(id);

  if (!entry) {
    store.set(id, { count: 1, resetAt: now + WINDOW_MS });
    return { ok: true };
  }

  if (now > entry.resetAt) {
    store.set(id, { count: 1, resetAt: now + WINDOW_MS });
    return { ok: true };
  }

  entry.count++;
  if (entry.count > REQUESTS) {
    return { ok: false, retryAfter: Math.ceil((entry.resetAt - now) / 1000) };
  }
  return { ok: true };
}

import { z } from "https://esm.sh/zod@3.23.8";

const uuidSchema = z.string().uuid();

export const photoToScopeSchema = z.object({
  zip_code: z.string().max(20).transform((s) => {
    const digits = s.replace(/\D/g, "").slice(0, 5);
    return digits.length >= 5 ? digits : "00000";
  }),
  room_type: z.string().transform((s) => {
    const v = s.toLowerCase();
    if (v === "kitchen") return "kitchen" as const;
    if (v === "bathroom" || v === "bath") return "bathroom" as const;
    return "other" as const;
  }),
  finish_preference: z.string().transform((s) => {
    const v = s.toLowerCase();
    return (v === "economy" || v === "premium" ? v : "mid") as "economy" | "mid" | "premium";
  }),
  project_id: z
    .string()
    .optional()
    .nullable()
    .transform((v) => {
      const s = (v ?? "").trim();
      if (!s) return null;
      const parsed = uuidSchema.safeParse(s);
      return parsed.success ? parsed.data : null;
    }),
  location_unset: z
    .string()
    .optional()
    .transform((v) => v === "1" || v === "true"),
  scope_description: z.string().max(2000).optional().nullable(),
});

const documentTypeSchema = z.enum(["invoice", "quote", "warranty", "permit"]).default("invoice");

export const uploadInvoiceSchema = z.object({
  project_id: uuidSchema,
  file: z
    .custom<File>((v) => v instanceof File && v.size > 0, "Valid file required")
    .refine((f) => f.size <= 10 * 1024 * 1024, "File must be under 10MB"),
  document_type: documentTypeSchema,
  vendor_hint: z.string().max(200).optional().nullable(),
  amount_hint: z.union([z.string(), z.number()]).optional().transform((v) => {
    if (v === "" || v == null) return null;
    const n = typeof v === "string" ? parseFloat(v) : v;
    return Number.isFinite(n) ? n : null;
  }),
});

export const getInvoiceSchema = z.object({
  invoice_id: uuidSchema,
});

import { createClient, type SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";

export function getServiceClient(): SupabaseClient {
  const url = Deno.env.get("SUPABASE_URL");
  const key = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!url || !key) throw new Error("Missing Supabase service configuration");
  return createClient(url, key);
}

export async function getUserIdFromRequest(req: Request): Promise<string | null> {
  const auth = req.headers.get("Authorization");
  if (!auth?.startsWith("Bearer ")) return null;
  const jwt = auth.slice(7);
  const url = Deno.env.get("SUPABASE_URL");
  const anon = Deno.env.get("SUPABASE_ANON_KEY");
  if (!url || !anon) return null;
  const supabase = createClient(url, anon);
  const { data: { user }, error } = await supabase.auth.getUser(jwt);
  if (error || !user) return null;
  return user.id;
}

export async function assertProjectOwner(
  admin: SupabaseClient,
  projectId: string,
  userId: string,
): Promise<void> {
  const { data: project, error: e1 } = await admin
    .from("projects")
    .select("property_id")
    .eq("id", projectId)
    .single();
  if (e1 || !project) throw new Error("not_found");
  const { data: prop, error: e2 } = await admin
    .from("properties")
    .select("owner_user_id")
    .eq("id", project.property_id)
    .single();
  if (e2 || !prop || prop.owner_user_id !== userId) throw new Error("forbidden");
}

/**
 * Gemini REST client for Supabase Edge (Deno).
 *
 * Official references (keep in sync when upgrading):
 * - Models: https://ai.google.dev/gemini-api/docs/models
 * - Text generation: https://ai.google.dev/gemini-api/docs/text-generation
 * - Tools overview: https://ai.google.dev/gemini-api/docs/tools
 * - Grounding with Google Search: https://ai.google.dev/gemini-api/docs/google-search
 *
 * Secrets (Supabase → Edge Functions → Secrets):
 * - GEMINI_API_KEY (required)
 * - GEMINI_MODEL (optional; default gemini-2.5-flash)
 */

export type GeminiPart = {
  text?: string;
  inline_data?: {
    mime_type: string;
    data: string;
  };
};

const DEFAULT_MODEL = "gemini-2.5-flash";
const API_VERSION = "v1beta";

function getGeminiModel(): string {
  // @ts-ignore: Deno global
  const fromEnv = Deno.env.get("GEMINI_MODEL")?.trim();
  return fromEnv || DEFAULT_MODEL;
}

/** Single user turn with multiple parts (text + inline data) per text-generation REST shape */
function buildContents(parts: GeminiPart[]) {
  const merged = parts.map((p) => {
    if (p.inline_data) {
      return {
        inlineData: {
          mimeType: p.inline_data.mime_type,
          data: p.inline_data.data,
        },
      };
    }
    return { text: p.text ?? "" };
  });
  return [{ role: "user", parts: merged }];
}

function readGroundingQueries(candidate: Record<string, unknown>): string[] | undefined {
  const gm = (candidate.groundingMetadata ?? candidate.grounding_metadata) as
    | Record<string, unknown>
    | undefined;
  if (!gm) return undefined;
  const q = gm.webSearchQueries ?? gm.web_search_queries;
  return Array.isArray(q) ? (q as string[]) : undefined;
}

export async function callGemini(params: {
  parts: GeminiPart[];
  systemInstruction?: string;
  model?: string;
  useGrounding?: boolean;
  responseMimeType?: "application/json" | "text/plain";
  responseSchema?: unknown;
  temperature?: number;
}): Promise<{
  text: string;
  data?: unknown;
  groundingMetadata?: unknown;
} | null> {
  // @ts-ignore: Deno global
  const apiKey = Deno.env.get("GEMINI_API_KEY");
  if (!apiKey?.trim()) {
    console.error("[callGemini] Missing GEMINI_API_KEY");
    return null;
  }

  const {
    parts,
    systemInstruction,
    model = getGeminiModel(),
    useGrounding = false,
    responseMimeType = "application/json",
    responseSchema,
    temperature = 0.1,
  } = params;

  try {
    const baseUrl = `https://generativelanguage.googleapis.com/${API_VERSION}/models/${model}:generateContent?key=${apiKey}`;

    const contents = buildContents(parts);

    // Built-in tool: Grounding with Google Search (not google_search_retrieval)
    const tools = useGrounding ? [{ google_search: {} }] : undefined;

    const generationConfig: Record<string, unknown> = {
      temperature,
      maxOutputTokens: 8192,
    };

    if (responseSchema) {
      generationConfig.responseMimeType = "application/json";
      generationConfig.responseSchema = responseSchema;
    } else {
      generationConfig.responseMimeType = responseMimeType;
    }

    const payload: Record<string, unknown> = {
      contents,
      generationConfig,
    };

    if (systemInstruction) {
      payload.systemInstruction = {
        parts: [{ text: systemInstruction }],
      };
    }

    if (tools) payload.tools = tools;

    const response = await fetch(baseUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Google API Error (${response.status}): ${errorText}`);
    }

    const result = (await response.json()) as Record<string, unknown>;
    const candidates = result.candidates as Record<string, unknown>[] | undefined;
    const candidate = candidates?.[0];
    if (!candidate) {
      console.warn("[callGemini] No candidates in response");
      return null;
    }

    const content = candidate.content as { parts?: Array<{ text?: string }> } | undefined;
    const firstText = content?.parts?.map((p) => p.text).filter(Boolean).join("") ?? "";
    const text = firstText.trim();

    if (!text) {
      console.warn("[callGemini] No response text in candidate");
      return null;
    }

    const groundingMetadata = candidate.groundingMetadata ?? candidate.grounding_metadata;
    const webQ = readGroundingQueries(candidate);
    if (webQ?.length) {
      console.log("[callGemini] Grounding web search queries:", webQ);
    }

    let data: unknown;
    if (responseMimeType === "application/json") {
      try {
        data = JSON.parse(text);
      } catch (e) {
        console.warn("[callGemini] JSON parse failed:", (e as Error).message);
      }
    }

    return {
      text,
      data,
      groundingMetadata,
    };
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : "Unknown Error";
    const errorMsg = `REST Error: ${msg}`;
    console.error(`[callGemini] ${errorMsg}`, e);
    return { text: `ERROR: ${errorMsg}` };
  }
}
